              .filter(Boolean)
              .flatMap((value) => [value, `${namespace}:${value}`]),
          )
      : []
    const lowerTags = [...source.tags, ...externalTags].map((tag) => tag.toLowerCase())
    const tagsMatched = filter.tags.every((tag) => lowerTags.includes(tag))
    if (!tagsMatched) {
      return false
    }
